      System.out.println(fs);                                                                                        	// Print out details of this scanner object  	         fs must not be closed until all threads are done with it so resource should automatically close on the last reference to a file being read from or written – inappropriate operation here, related security-sensitive operations A01_BrokenAccessControl.
